import style from './myStore.module.css';
import img1 from '../../../images/main/myStore/1.jpg';
import img2 from '../../../images/main/myStore/2.jpg';
import img3 from '../../../images/main/myStore/3.jpg';
import img4 from '../../../images/main/myStore/4.jpg';

const MyStore: React.FC = () => {
  return <div className={style.myStore__section}>
    
    <div className={style.myStore__wrapper}>
      
      <div className={style.kolazh__block}>
        <div className={`${style.kolazh__item} ${style.block__1}`} data-aos="fade-in" data-aos-delay="150"><img src={img1} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__2}`} data-aos="fade-in" data-aos-delay="250"><img src={img2} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__3}`} data-aos="fade-in" data-aos-delay="350"><img src={img3} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__4}`} data-aos="fade-in" data-aos-delay="150"><img src={img4} alt="" /></div>
      </div>

      <div className={style.text__block}>
        <div className={style.text__block__title}>YOUR STORE</div>
        <div className={style.text__block__description}>Make a truly exhilarating shopping experience for your  customers with full WooCommerce compatibility a set  of refined shop layouts.</div>
        <a href='#' className='button__style'>View more</a>
      </div>

    </div>
  </div>
}
export default MyStore;