import style from './booking.module.css';
import img1 from '../../../images/main/booking/1.jpg';
import img2 from '../../../images/main/booking/2.jpg';
import img3 from '../../../images/main/booking/3.png';
import img4 from '../../../images/main/booking/4.png';

const Booking: React.FC = () => {
  return <div className={style.booking__section}>
    <div className={style.booking__wrapper}>

      <div className={style.text__block}>
        <div className={style.text__block__title} data-aos="fade-in" data-aos-delay="150">BOOKING</div>
        <div className={style.text__block__description} data-aos="fade-in" data-aos-delay="250">The reservation process is sure to go smoothly with Chea! Let customers easily book treatments that your spa and wellness center offers.</div>
        <a href='#' className='button__style' data-aos="fade-in" data-aos-delay="350">View more</a>
      </div>

      <div className={style.kolazh__block}>
        <div className={`${style.kolazh__item} ${style.block__1}`} data-aos="fade-left" data-aos-delay="150"><img src={img1} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__2}`} data-aos="fade-down" data-aos-delay="250"><img src={img2} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__3}`} data-aos="fade-right" data-aos-delay="350"><img src={img3} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__4}`} data-aos="fade-in" data-aos-delay="450"><img src={img4} alt="" /></div>
      </div>

    </div>
  </div>
}
export default Booking;