import style from './chea.module.css';
const Chea: React.FC = () => {
  return <div className={style.chea__section}>

    <div className={style.chea__title}>
      <div className={style.chea__title__wrapper}>
        <div className={style.title__text}>
          <div className={style.text__big} data-aos="fade-up">CHEA</div>
          <div className={style.text__long} data-aos="fade-up">Chea`s refreshind of fully built websites is ideal for your spa and wellness business. Your site with Chea - a true reflection of peace</div>
        </div>

        <div className={style.chea__theme_animate} data-aos="fade-in">
          <div >Get Theme</div>
        </div>
      </div>
    </div>
    
  </div>
}
export default Chea;