import style from './main-section.module.css';
import Chea from './chea-section/chea';
import PhotosSection from './photos-section/photos-section';
import Kolazh from './kolazh-section/kolazh';
import SpaSection from './spa-section/spa-section';
import MyStory from './store-section/myStore';
import Booking from './booking-section/booking';
import InnerSection from './inner-section/inner';
import Footer from '../footer/footer';

const MainSection: React.FC = () => {
  return <div className={style.main__section}>
    <Chea />
    <PhotosSection />
    <Kolazh />
    <SpaSection />
    <MyStory />
    <Booking />
    <div className={style.footer__wrapper}>
      <InnerSection />
      <Footer />
    </div>
  </div>
}
export default MainSection;