import style from './kolazh.module.css';
import img1 from '../../../images/main/kolazh/1.jpg'
import img2 from '../../../images/main/kolazh/2.png'
import img3 from '../../../images/main/kolazh/3.jpg'
import img4 from '../../../images/main/kolazh/4.jpg'
import img5 from '../../../images/main/kolazh/5.jpg'

const Kolazh: React.FC = () => {
  return <div className={style.kolazh__section}>

    <div className={style.wrapper__text}>
      <div className={style.kolazh__circle}>''</div>
      <div className={style.kolazh__title} data-aos="fade-in" data-aos-delay="150">
        <div className={style.kolazh__text} data-aos="fade-in" data-aos-delay="250">
          With Chea`s splendid premade blog layout diverse post types you`ll be able to make the perfect blog. Share wellness tips news with your followers.
        </div>
      </div>
    </div>

    <div className={style.kolazh} >
      <div className={style.kolazh__items__wrapper}>
        <div className={`${style.kolazh__item} ${style.block__1}`} data-aos="fade-in" data-aos-delay="150"><img src={img1} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__2}`} data-aos="fade-up-right" data-aos-delay="250"><img src={img2} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__3}`} data-aos="fade-up-in" data-aos-delay="150"><img src={img3} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__4}`} data-aos="fade-left" data-aos-delay="250"><img src={img4} alt="" /></div>
        <div className={`${style.kolazh__item} ${style.block__5}`} data-aos="fade-in" data-aos-delay="150"><img src={img5} alt="" /></div>
      </div>
    </div>
    
  </div>
}
export default Kolazh;