import style from './chat.module.scss';
import { useState } from 'react';

const Chat: React.FC = () => {
  const [open, setOpen] = useState(false);
  const HandleOpen = () => setOpen(true);
  const HandleClose = () => setOpen(false);
  return <div className={style.chat__element}>
    {open ?
      <div className={style.active__chat}>
        <div className={style.chat__header}>
          Live chat <span style={{cursor:'pointer'}} onClick={HandleClose}> - </span>
        </div>
      </div>
      :
      <div className={style.chat__button} onClick={HandleOpen}>
        <div className={style.chat__icon}>
          <img className={style.icon__image} src='https://upload.wikimedia.org/wikipedia/commons/thumb/3/3c/Chat_white.svg/1200px-Chat_white.svg.png' alt="" />
        </div>
        <div>Чат</div>
      </div>}



  </div>
}
export default Chat;